import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Bell, CheckCheck, Trash2 } from 'lucide-react';
import { formatRelativeTime } from '../utils/helpers';
import useNotifications from '../hooks/useNotifications';
import { notificationsApi } from '../services/api';
import toast from 'react-hot-toast';

const TYPE_ICONS = {
  TASK_ASSIGNED:            '📋',
  REVIEW_REQUESTED:         '🔍',
  REVIEW_APPROVED:          '✅',
  REVIEW_CHANGES_REQUESTED: '🔄',
  COMMENT_ADDED:            '💬',
  MEMBER_ADDED:             '👥',
  TASK_DUE_SOON:            '⏰',
};

export default function NotificationsPage() {
  const navigate = useNavigate();
  const { notifications, loading, unreadCount, markRead, markAllRead } = useNotifications();

  const handleClick = async (n) => {
    if (!n.isRead) await markRead(n._id);
    if (n.link) navigate(n.link);
  };

  const handleDelete = async (e, id) => {
    e.stopPropagation();
    try {
      await notificationsApi.delete(id);
      toast.success('Notification removed');
      window.location.reload(); // simple refresh — swap for state update in production
    } catch { toast.error('Failed to delete'); }
  };

  return (
    <div style={{ maxWidth: 680, margin: '0 auto' }}>
      <div className="page-header">
        <div>
          <h1>Notifications</h1>
          {unreadCount > 0 && (
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: 4 }}>
              {unreadCount} unread
            </p>
          )}
        </div>
        {unreadCount > 0 && (
          <button className="btn btn-secondary btn-sm" onClick={markAllRead}>
            <CheckCheck size={14} /> Mark all read
          </button>
        )}
      </div>

      {loading ? (
        <div className="empty-state"><div className="spinner spinner-lg" /></div>
      ) : notifications.length === 0 ? (
        <div className="empty-state">
          <Bell size={48} />
          <h3>All caught up</h3>
          <p>No notifications yet. We'll let you know when something happens.</p>
        </div>
      ) : (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          {notifications.map((n, i) => (
            <div
              key={n._id}
              className={`notification-item${!n.isRead ? ' unread' : ''}`}
              style={{ borderBottom: i < notifications.length - 1 ? '1px solid var(--border)' : 'none' }}
              onClick={() => handleClick(n)}
            >
              <div style={{ fontSize: '1.2rem', flexShrink: 0, marginTop: 2 }}>
                {TYPE_ICONS[n.type] || '🔔'}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 8 }}>
                  <p className="notification-title">{n.title}</p>
                  {!n.isRead && <div className="notification-dot" style={{ flexShrink: 0, marginTop: 7 }} />}
                </div>
                <p className="notification-message">{n.message}</p>
                <p className="notification-time">{formatRelativeTime(n.createdAt)}</p>
              </div>
              <button
                className="btn btn-ghost btn-icon btn-sm"
                style={{ flexShrink: 0, alignSelf: 'center' }}
                onClick={(e) => handleDelete(e, n._id)}
              >
                <Trash2 size={13} />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
